import{experienceData,educationData}from"./mock-data/data.js";const carouselTrack=document.getElementById("carouselTrack"),timelineDotsContainer=document.getElementById("timelineDots"),tabs=document.querySelectorAll(".tab"),prevButton=document.querySelector(".nav-button.prev"),nextButton=document.querySelector(".nav-button.next");let currentIndex=0,currentTab="experience";function getCurrentData(){return"experience"===currentTab?experienceData:educationData}function renderTimeline(){const e=getCurrentData();carouselTrack.innerHTML=e.map((e,t)=>`\n                    <div class="carousel-item ${t===currentIndex?"active":""}">\n                        <div class="job-title">${e.title}</div>\n                        <div class="company">${e.company}</div>\n                        <div class="location">${e.location}</div>\n                        <div class="tech-stack">${e.tech}</div>\n                    </div>\n                `).join(""),timelineDotsContainer.innerHTML=e.map((e,t)=>`<div class="timeline-dot ${t===currentIndex?"active":""}" data-index="${t}"></div>`).join(""),updatePosition(),updateButtonStates(),document.querySelectorAll(".timeline-dot").forEach(e=>{e.addEventListener("click",()=>{currentIndex=parseInt(e.getAttribute("data-index")),renderTimeline()})})}function renderPrintSections(){const e=document.getElementById("printExperience"),t=document.getElementById("printEducation");e.innerHTML=experienceData.map(e=>`\n                    <div class="print-item">\n                        <div class="job-title">${e.title}</div>\n                        <div class="company">${e.company}</div>\n                        <div class="location">${e.location}</div>\n                        <div class="tech-stack">${e.tech}</div>\n                    </div>\n                `).join(""),t.innerHTML=educationData.map(e=>`\n                    <div class="print-item">\n                        <div class="job-title">${e.title}</div>\n                        <div class="company">${e.company}</div>\n                        <div class="location">${e.location}</div>\n                        <div class="tech-stack">${e.tech}</div>\n                    </div>\n                `).join("")}function updatePosition(){const e=carouselTrack.querySelectorAll(".carousel-item");if(0===e.length)return;const t=window.innerWidth<=768,n=e[0].offsetWidth,i=t?40:100;let a;if(t){carouselTrack.scrollWidth;a=carouselTrack.parentElement.offsetWidth/2-n/2-currentIndex*(n+i)}else{a=-currentIndex*(n+i),a+=carouselTrack.parentElement.offsetWidth/2-n/2}carouselTrack.style.transform=`translateX(${a}px)`}function updateButtonStates(){const e=getCurrentData(),t=0===currentIndex,n=currentIndex===e.length-1;prevButton.style.opacity=t?"0.3":"1",prevButton.style.cursor=t?"default":"pointer",prevButton.disabled=t,nextButton.style.opacity=n?"0.3":"1",nextButton.style.cursor=n?"default":"pointer",nextButton.disabled=n,t?prevButton.classList.add("disabled"):prevButton.classList.remove("disabled"),n?nextButton.classList.add("disabled"):nextButton.classList.remove("disabled")}function navigate(e){const t=getCurrentData(),n=currentIndex;"next"===e&&currentIndex<t.length-1?currentIndex++:"prev"===e&&currentIndex>0&&currentIndex--,n!==currentIndex&&renderTimeline()}prevButton.addEventListener("click",()=>navigate("prev")),nextButton.addEventListener("click",()=>navigate("next")),tabs.forEach(e=>{e.addEventListener("click",()=>{tabs.forEach(e=>e.classList.remove("active")),e.classList.add("active"),currentTab=e.getAttribute("data-tab"),currentIndex=0,renderTimeline()})}),window.addEventListener("resize",updatePosition),window.addEventListener("resize",()=>{updatePosition(),updateButtonStates()}),renderTimeline(),renderPrintSections();